/// GET v1/{+parent}/products/{+name}
/// Inserts or updates the attributes of the product in a Manufacturer Center account. Creates a product with the provided attributes. If the product already exists, then all attributes are replaced with the new ones. The checks at upload time are minimal. All required attributes need to be present for a product to be valid. Issues may show up later after the API has accepted a new upload for a product and it is possible to overwrite an existing valid product with an invalid product. To detect this, you should retrieve the product and check it for issues once the new version is available. Uploaded attributes first need to be processed before they can be retrieved. Until then, new products will be unavailable, and retrieval of previously uploaded products will return the original state of the product.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `manufacturers_accounts_products_update_execute()` to send, or `manufacturers_accounts_products_update` for simplest API.

pub fn manufacturers_accounts_products_update_builder(
    client: &SimpleHttpClient,
    name: &str,
    parent: &str,
    body: &Attributes,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!(
        "https://api.example.comv1/{+parent}/products/{+name}",
        name, parent,
    );

    // Build request
    client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
        .body_json(body)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
}

/// GET v1/{+parent}/products/{+name}
/// Inserts or updates the attributes of the product in a Manufacturer Center account. Creates a product with the provided attributes. If the product already exists, then all attributes are replaced with the new ones. The checks at upload time are minimal. All required attributes need to be present for a product to be valid. Issues may show up later after the API has accepted a new upload for a product and it is possible to overwrite an existing valid product with an invalid product. To detect this, you should retrieve the product and check it for issues once the new version is available. Uploaded attributes first need to be processed before they can be retrieved. Until then, new products will be unavailable, and retrieval of previously uploaded products will return the original state of the product.
///
/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `manufacturers_accounts_products_update_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from manufacturers_accounts_products_update_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn manufacturers_accounts_products_update_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<Empty>, ApiError>, P = ApiPending> + Send + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success { stream, status } => {
                let headers = status.headers().clone();

                if !status.is_success() {
                    return Err(ApiError::HttpStatus {
                        code: status.as_u16(),
                        headers,
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: Empty = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status.as_u16(),
                    headers,
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

